class DeviceController:
    def __init__(self, pin_num=2, active_high=True):
        self.pin = machine.Pin(pin_num, machine.Pin.OUT)
        self.active_high = active_high
        self.state = False
        self.turn_off()

    def _write(self, on):
        self.state = bool(on)
        v = 1 if self.state else 0
        if not self.active_high:
            v ^= 1
        self.pin.value(v)

    def turn_on(self):
        self._write(True)

    def turn_off(self):
        self._write(False)

    def toggle(self):
        self._write(not self.state)

    def status(self):
        return {"on": self.state}


async def default_on_json(conn, msg, controller):
    action = msg.get("action")
    if action == "turn_on":
        controller.turn_on()
        conn.send_json({"ok": True, "state": controller.status()})
    elif action == "turn_off":
        controller.turn_off()
        conn.send_json({"ok": True, "state": controller.status()})
    elif action == "toggle":
        controller.toggle()
        conn.send_json({"ok": True, "state": controller.status()})
    elif action == "status":
        conn.send_json({"ok": True, "state": controller.status()})
    else:
        conn.send_json({"ok": False, "error": "unknown_action", "action": action})


async def default_on_connect(conn, controller):
    try:
        conn.send_json({"event": "connected", "state": controller.status()})
    except:
        pass


def connect_wifi(ssid, password, hostname="esp32-ws", timeout_s=15):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    try:
        wlan.config(dhcp_hostname=hostname)
    except:
        pass
    if not wlan.isconnected():
        wlan.connect(ssid, password)
        t0 = time.ticks_ms()
        while not wlan.isconnected():
            if time.ticks_diff(time.ticks_ms(), t0) > timeout_s * 1000:
                raise RuntimeError("WiFi connect timeout")
            time.sleep_ms(200)
    return wlan


async def main(ssid, password, ws_port=80, ws_path="/ws", pin_num=2, active_high=True, allow_origin="*"):
    connect_wifi(ssid, password)
    controller = DeviceController(pin_num=pin_num, active_high=active_high)

    async def on_json(conn, msg):
        await default_on_json(conn, msg, controller)

    async def on_connect(conn):
        await default_on_connect(conn, controller)

    server = WebSocketServer(
        host="0.0.0.0",
        port=ws_port,
        path=ws_path,
        on_json=on_json,
        on_connect=on_connect,
        ping_interval=20,
        allow_origin=allow_origin
    )
    await server.start()
    while True:
        await asyncio.sleep(3600)


